import{_ as t,o,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"93. Proposals To Vary Specific Matters","description":"","frontmatter":{"title":"93. Proposals To Vary Specific Matters","eba":"Nurses and Midwives 2024-2028","topics":["hours","allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.md","filePath":"ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.md"}'),a={name:"ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.md"};function n(i,e,p,l,h,c){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_93-proposals-to-vary-specific-matters" tabindex="-1">93. Proposals To Vary Specific Matters <a class="header-anchor" href="#_93-proposals-to-vary-specific-matters" aria-label="Permalink to &quot;93. Proposals To Vary Specific Matters&quot;">​</a></h1><p><strong>93.1</strong> Application</p><p><strong>(a)</strong> This clause will apply to any proposal by an Employer or Employees to:</p><p><strong>(i)</strong> implement an alternate Four Clear Days Allowance (see clause 41C.);</p><p><strong>(ii)</strong> implement alternative hours of work at <a href="/eba/ebas/nurses-midwives/hours-of-work/42-hours-of-work.html">clause 42</a> (Hours of Work), (excepting <a href="/eba/ebas/nurses-midwives/hours-of-work/42-hours-of-work.html">clauses 42.2</a>, 42.3, and 42.4); or</p><p><strong>(iii)</strong> increase the number of rostered short shifts beyond the limit set by <a href="/eba/ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.html">clause 47</a> (Avoidance and Management of Short Shifts) where the use of short shifts beyond that limit would have an EFT neutral effect.</p><p><strong>(b)</strong> Nothing in this clause:</p><p><strong>(i)</strong> allows for the unilateral changing of an Employee&#39;s contract of employment; or</p><p><strong>(ii)</strong> permits variations inconsistent with the minimum ratio requirements prescribed by or made under the Safe Patient Care Act.</p><p><strong>93.2</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> Affected Employee means an Employee in the ward or unit to which the proposal relates.</p><p><strong>(b)</strong> EFT neutral means there is no reduction in nursing hours in a ward or unit as a result of the proposal to exceed the rostered short shift limit at <a href="/eba/ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.html">clause 47</a> (Avoidance and Management of Short Shifts). That is, the nursing hours lost as a result of the additional short shifts are returned to the ward as part of the Proposal within the week of the applicable short shift unless otherwise agreed with the Affected Employees.</p><p><strong>93.3</strong> Written proposal (complying and non-complying proposal)</p><p>The Employer will provide a written proposal to the Affected Employees and, at the same time, the Secretary of the ANMF. The proposal will address, where relevant, the considerations referred to in clause 93.9 below.</p><p><strong>93.4</strong> Meaning of Complying Proposal</p><p>In this clause, a complying proposal is a proposal that:</p><p><strong>(a)</strong> is EFT neutral;</p><p><strong>(b)</strong> would, upon implementation, be compliant with the ratios prescribed by Divisions 1, 2 and 3 in Part 2 the Safe Patient Care Act; and</p><p><strong>(c)</strong> is not a non-complying proposal as described at clause 93.7 below.</p><p><strong>93.5</strong> Consultation period – complying proposal</p><p>A maximum of three weeks from the date of provision of the information in clause 93.3 will be provided for consultation.</p><p><strong>93.6</strong> Implementing a complying proposal</p><p><strong>(a)</strong> Genuine majority agree</p><p>Except as provided at (c), below, where a genuine majority of Affected Employees agree to a complying proposal at the local level it may be implemented from the beginning of the next roster period. Such agreement will not be unreasonably withheld.</p><p><strong>(b)</strong> Disputes</p><p>Should there be concern as to the &#39;genuine&#39; nature of the agreement of the affected Employee, or agreement being unreasonably withheld, either party may progress such concerns through the Dispute Resolution Procedure within seven days of the view of the Affected Employees being determined. While the Dispute Resolution Procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>(c)</strong> Exception – flexible work arrangement</p><p>The requirement at subclause 93.6(a) does not apply where the complying proposal is facilitating a flexible work arrangement within the meaning of clause 16 (Flexible Working Arrangements). Following the consultation period at clause 93.5, a complying proposal facilitating a flexible work arrangement may be implemented from the beginning of the next roster period.</p><p><strong>93.7</strong> Meaning of Non-Complying Proposal</p><p>In this clause, a non-complying proposal is a proposal about a matter at subclause 93.1(a) that:</p><p><strong>(a)</strong> is not EFT neutral;</p><p><strong>(b)</strong> is non-compliant with the ratios prescribed by Divisions 1, 2 and 3 in Part 2 of the Safe Patient Care Act and, to be implemented would require a variation to the ratios using a method under Part 2, Division 4 of the Safe Patient Care Act;</p><p><strong>(c)</strong> reduces shift length; or</p><p><strong>(d)</strong> includes 12-hour shifts.</p><p><strong>93.8</strong> Implementation of a non-complying proposal</p><p><strong>(a)</strong> A maximum of one month from the date of provision of the written proposal will be provided for consultation.</p><p><strong>(b)</strong> Where the Employer, the ANMF and the affected Employees agree, the proposal may be implemented from the beginning of the next roster period except where it is also necessary for a variation of ratios to be made under the Safe Patient Care Act. In order for the proposal to be effective the proposal will not be implemented until the ratio variation under the Safe Patient Care Act takes effect.</p><p><strong>(c)</strong> Where the Employee(s) do not agree with an Employer&#39;s proposal, a secret ballot of affected Employees will be conducted. If the ballot does not endorse the proposed change, then the proposal will not proceed.</p><p><strong>93.9</strong> Considerations</p><p>The following are considerations, where relevant, that must be addressed in relation to a proposal referred to in clause 93.1:</p><p><strong>(a)</strong> patient profile – consideration of patient case mix, age of patient, complexity, length of stay and throughput of patients in the clinical setting e.g. emergency admissions, elective admissions and transfers to/from critical care areas;</p><p><strong>(b)</strong> the capacity of nursing/midwifery staff to complete their duties within existing work hours;</p><p><strong>(c)</strong> quality of care/clinical risk, including nurse/midwife sensitive adverse outcomes such as falls (with or without injury), urinary tract infections, pneumonia, decubitus ulcers, thrombosis, sepsis and medication errors (with or without patient consequences);</p><p><strong>(d)</strong> occupational health and safety considerations such as physical environment and staff safety; and</p><p><strong>(e)</strong> nursing/midwifery engagement.</p><p><strong>93.10</strong> Preservation of Existing Workload Management Proposals</p><p>A Workload Management proposal that was implemented prior to this Agreement coming into operation remains in effect, subject to the terms of this Agreement.</p>',48)])])}const g=t(a,[["render",n]]);export{m as __pageData,g as default};
